const inputs = $input.all();

function unescapeIfNeeded(s) {
  if (typeof s !== 'string') return s;
  if (s.includes('\\"') || s.includes('\\n')) {
    return s
      .replace(/\\n/g, '\n')
      .replace(/\\t/g, '\t')
      .replace(/\\"/g, '"')
      .replace(/\\\\/g, '\\');
  }
  return s;
}

function safeJsonParse(text) {
  try {
    return JSON.parse(text);
  } catch (e) {
    return null;
  }
}

function pickArray(parsed) {
  // parsed can be [] or {} or {output:[]} or {new_items:[]}
  if (!parsed) return [];
  if (Array.isArray(parsed)) return parsed;

  if (Array.isArray(parsed.output)) return parsed.output;
  if (Array.isArray(parsed.new_items)) return parsed.new_items;
  if (Array.isArray(parsed.items)) return parsed.items;

  // sometimes nested like { output: { new_items: [] } }
  if (parsed.output && typeof parsed.output === 'object') {
    if (Array.isArray(parsed.output.output)) return parsed.output.output;
    if (Array.isArray(parsed.output.new_items)) return parsed.output.new_items;
    if (Array.isArray(parsed.output.items)) return parsed.output.items;
  }

  return [];
}

function clean(v) {
  if (v === undefined || v === null) return null;
  const s = String(v).trim();
  return s === '' ? null : s;
}

function normalizePhone(p) {
  if (!p) return null;
  const s = String(p).trim();
  // if already contains () or + keep it
  if (/[()+\-\s]/.test(s)) return s;

  // if digits only, format US 10 digits
  const digits = s.replace(/\D/g, '');
  if (digits.length === 10) {
    return `(${digits.slice(0,3)}) ${digits.slice(3,6)}-${digits.slice(6)}`;
  }
  return s;
}

const out = [];

for (let i = 0; i < inputs.length; i++) {
  const raw0 = inputs[i].json?.output;

  if (typeof raw0 !== 'string') continue;

  const raw = unescapeIfNeeded(raw0);
  const parsed = safeJsonParse(raw);

  const arr = pickArray(parsed);

  for (const it of arr) {
    const row = {
      name: clean(it?.name ?? it?.["Business name"] ?? it?.title),
      address: clean(it?.address ?? it?.["Full Address"] ?? it?.full_address ?? it?.fullAddress),
      phone: clean(normalizePhone(it?.phone ?? it?.["Phone number"] ?? it?.phonenumber)),
      email: clean(it?.email ?? it?.["Email"]),
      website: clean(it?.website ?? it?.["Website"] ?? it?.url),
      facebook: clean(it?.facebook ?? it?.["Facebook link"]),
      instagram: clean(it?.instagram ?? it?.["Instagram link"]),
      tiktok: clean(it?.tiktok ?? it?.["Tiktok link"]),
      youtube: clean(it?.youtube ?? it?.["Youtube link"]),
      twitter: clean(it?.twitter ?? it?.["Twitter link"]),
    };

    // skip if completely empty
    if (Object.values(row).some(v => v !== null)) {
      out.push({ json: row, pairedItem: { item: i } });
    }
  }
}

if (out.length === 0) {
  return [{
    json: {
      error: "No rows extracted",
      hint: "AI Agent output string was {} or [] or not valid JSON",
      sample: inputs[0]?.json?.output ?? null
    }
  }];
}

return out;

